// means "no limit" in SQLite, so OFFSET skips the keepers.
func (q *Queries) PruneContentsCacheLRU(ctx context.Context, offset int64) error {
	_, err := q.db.ExecContext(ctx, pruneContentsCacheLRU, offset)
	return err
}

